   1 | import { SearchIndex } from "./search-index.js";
   2 | import { VectorIndex } from "./vector-index.js";
   3 | import type { StateKV } from "./kv.js";
   4 | import { KV } from "./schema.js";
   5 | import { logger } from "../logger.js";
   6 | 
   7 | const DEBOUNCE_MS = 5000;
   8 | const FAILURE_LOG_THROTTLE_MS = 60_000;
   9 | 
  10 | export class IndexPersistence {
  11 |   private timer: ReturnType<typeof setTimeout> | null = null;
  12 |   private lastFailureLogAt = 0;
  13 | 
  14 |   constructor(
  15 |     private kv: StateKV,
  16 |     private bm25: SearchIndex,
  17 |     private vector: VectorIndex | null,
  18 |   ) {}
  19 | 
  20 |   scheduleSave(): void {
  21 |     if (this.timer) clearTimeout(this.timer);
  22 |     // setTimeout discards the returned promise, so any rejection inside
  23 |     // save() would surface as unhandledRejection and crash the process
  24 |     // under sustained iii-engine write timeouts (issue #204). Funnel
  25 |     // rejections through logFailure() instead.
  26 |     this.timer = setTimeout(() => {
  27 |       this.save().catch((err) => this.logFailure(err));
  28 |     }, DEBOUNCE_MS);
  29 |   }
  30 | 
  31 |   async save(): Promise<void> {
  32 |     if (this.timer) {
  33 |       clearTimeout(this.timer);
  34 |       this.timer = null;
  35 |     }
  36 |     try {
  37 |       await this.kv.set(KV.bm25Index, "data", this.bm25.serialize());
  38 |       if (this.vector && this.vector.size > 0) {
  39 |         await this.kv.set(KV.bm25Index, "vectors", this.vector.serialize());
  40 |       }
  41 |     } catch (err) {
  42 |       this.logFailure(err);
  43 |     }
  44 |   }
  45 | 
  46 |   async load(): Promise<{
  47 |     bm25: SearchIndex | null;
  48 |     vector: VectorIndex | null;
  49 |   }> {
  50 |     let bm25: SearchIndex | null = null;
  51 |     let vector: VectorIndex | null = null;
  52 | 
  53 |     const bm25Data = await this.kv
  54 |       .get<string>(KV.bm25Index, "data")
  55 |       .catch(() => null);
  56 |     if (bm25Data && typeof bm25Data === "string") {
  57 |       bm25 = SearchIndex.deserialize(bm25Data);
  58 |     }
  59 | 
  60 |     const vecData = await this.kv
  61 |       .get<string>(KV.bm25Index, "vectors")
  62 |       .catch(() => null);
  63 |     if (vecData && typeof vecData === "string") {
  64 |       vector = VectorIndex.deserialize(vecData);
  65 |     }
  66 | 
  67 |     return { bm25, vector };
  68 |   }
  69 | 
  70 |   stop(): void {
  71 |     if (this.timer) {
  72 |       clearTimeout(this.timer);
  73 |       this.timer = null;
  74 |     }
  75 |   }
  76 | 
  77 |   private logFailure(err: unknown): void {
  78 |     const now = Date.now();
  79 |     // Throttle: persistence failures under load arrive in bursts
  80 |     // (iii-engine queue pressure). Logging every debounce flush adds
  81 |     // noise without information.
  82 |     if (now - this.lastFailureLogAt < FAILURE_LOG_THROTTLE_MS) return;
  83 |     this.lastFailureLogAt = now;
  84 |     const code = (err as { code?: string })?.code;
  85 |     const message = err instanceof Error ? err.message : String(err);
  86 |     logger.warn("index persistence: failed to save BM25/vector index", {
  87 |       code,
  88 |       message,
  89 |       hint:
  90 |         code === "TIMEOUT"
  91 |           ? "iii-engine state::set timed out; recent index updates remain in memory and will retry on the next debounce flush"
  92 |           : undefined,
  93 |     });
  94 |   }
  95 | }
--- 读取完毕 ---

